Here's a modern MSTest approach using `HttpMessageHandler` faking and async patterns:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    // Async tests: just return Task — MSTest awaits them natively.
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("hello")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    // Timeout: use [Timeout] or a CancellationToken with a deadline.
    [TestMethod]
    [Timeout(3000)] // fails the test if it runs longer than 3 seconds
    public async Task FetchAsync_ThrowsOnTimeout()
    {
        var handler = new FakeHandler(async (_, ct) =>
        {
            await Task.Delay(Timeout.Infinite, ct); // simulate a hung server
            return new HttpResponseMessage();        // unreachable
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(100));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Cancellation: verify the token is respected.
    [TestMethod]
    public async Task FetchAsync_ThrowsWhenAlreadyCancelled()
    {
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK));
        var fetcher = new DataFetcher(new HttpClient(handler));

        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Error status codes
    [TestMethod]
    public async Task FetchAsync_ThrowsOnServerError()
    {
        var handler = new FakeHandler(
            new HttpResponseMessage(HttpStatusCode.InternalServerError));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // --- Minimal fake handler ---

    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly Func<HttpRequestMessage, CancellationToken,
            Task<HttpResponseMessage>> _send;

        public FakeHandler(HttpResponseMessage response)
            : this((_, _) => Task.FromResult(response)) { }

        public FakeHandler(
            Func<HttpRequestMessage, CancellationToken,
                Task<HttpResponseMessage>> send) => _send = send;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => _send(request, cancellationToken);
    }
}
```

**Key patterns:**

| Pattern | How |
|---|---|
| **Async tests** | Return `Task`, use `async`/`await` — no `.Result` or `.Wait()` |
| **Timeouts** | `[Timeout(ms)]` attribute or pass a deadline via `CancellationTokenSource(TimeSpan)` |
| **Cancellation** | Pre-cancel a `CancellationTokenSource`, assert `TaskCanceledException` |
| **No real HTTP** | Fake `HttpMessageHandler` — avoids network calls and lets you control responses |

Avoid `[Timeout]` on every test — prefer it only for tests that could genuinely hang. For normal assertions, the default test runner timeout is sufficient.
